$headers = @{ 'Authorization' = "Bearer $env:NOTION_TOKEN"; 'Notion-Version' = '2022-06-28'; 'Content-Type'='application/json' }
function Get-TableText($id){
  $r = Invoke-RestMethod -Method Get -Uri "https://api.notion.com/v1/blocks/$id/children?page_size=100" -Headers $headers
  foreach($row in $r.results){
    if($row.type -eq 'table_row'){
      $cells = @()
      foreach($cell in $row.table_row.cells){
        $txt = ($cell | ForEach-Object { $_.plain_text }) -join ''
        $cells += $txt
      }
      [PSCustomObject]@{id=$row.id; cells=$cells}
    }
  }
}
